class Command(BaseCommand):
    help = '匯入 EASYBUY 預設商品資料'

    def handle(self, *args, **options):
        created = 0
        updated = 0
        for data in PRODUCTS:
            obj, was_created = Product.objects.update_or_create(
                external_id=data['external_id'],
                defaults=data,
            )
            if was_created:
                created += 1
            else:
                updated += 1
        self.stdout.write(self.style.SUCCESS(f'商品匯入完成：新增 {created} 筆，更新 {updated} 筆'))
